hooks.command:
echo "$TOOL_INPUT" | python3 -c "
import sys, json
try:
    data = json.load(sys.stdin)
    cmd = data.get('command', '')
    if 'git commit' in cmd:
        print('[docs] Pre-commit: which reference docs, user-docs, or guides describe the behaviour you just changed? Are they updated in this commit?')
except Exception:
    pass
" 2>/dev/null || true
